import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testValueOf_withValidFormat() throws Exception {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat predefinedFormat = CSVFormat.DEFAULT;
            CSVFormat predefinedReturnedFormat = predefinedFormat.withAllowMissingColumnNames();

            CSVFormat.Predefined predefined = Mockito.mock(CSVFormat.Predefined.class);
            Mockito.when(predefined.getFormat()).thenReturn(predefinedReturnedFormat);
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("DEFAULT")).thenReturn(predefined);

            CSVFormat result = CSVFormat.valueOf("DEFAULT");
            assertNotNull(result);
            assertEquals(predefinedReturnedFormat, result);

            // Also verify that the static method was called correctly
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("DEFAULT"));
            Mockito.verify(predefined).getFormat();
        }
    }

    @Test
    public void testValueOf_withDifferentFormat() throws Exception {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat predefinedReturnedFormat = CSVFormat.EXCEL;

            CSVFormat.Predefined predefined = Mockito.mock(CSVFormat.Predefined.class);
            Mockito.when(predefined.getFormat()).thenReturn(predefinedReturnedFormat);
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("EXCEL")).thenReturn(predefined);

            CSVFormat result = CSVFormat.valueOf("EXCEL");
            assertNotNull(result);
            assertEquals(predefinedReturnedFormat, result);

            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("EXCEL"));
            Mockito.verify(predefined).getFormat();
        }
    }

    @Test
    public void testValueOf_reflection_invocation() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("valueOf", String.class);
        method.setAccessible(true);

        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat predefinedReturnedFormat = CSVFormat.RFC4180;

            CSVFormat.Predefined predefined = Mockito.mock(CSVFormat.Predefined.class);
            Mockito.when(predefined.getFormat()).thenReturn(predefinedReturnedFormat);
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("RFC4180")).thenReturn(predefined);

            Object result = method.invoke(null, "RFC4180");
            assertNotNull(result);
            assertTrue(result instanceof CSVFormat);
            assertEquals(predefinedReturnedFormat, result);

            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("RFC4180"));
            Mockito.verify(predefined).getFormat();
        }
    }
}
